number_boxed_total.script:
				function onInit()
					addSource("bonus");
					addSource("race");
					addSource("special");
					super.onInit();
				end

				function onSourceUpdate()
					local nValue = calculateSources();
					local node = window.getDatabaseNode();
					nValue = nValue + DB.getValue(node, "bonus", 0);
					nValue = nValue + DB.getValue(node, "race", 0);
					nValue = nValue + DB.getValue(node, "special", 0);
					setValue(nValue);
				end

				function onDoubleClick(x, y)
					ModifierStack.addSlot(window.label.getValue(), getValue());
				end

				function onDragStart(button, x, y, draginfo)
					draginfo.setType("number");
					draginfo.setDescription(window.label.getValue().." Bonus");
					if getValue() >= 0 then
						draginfo.setStringData(window.label.getValue().." Bonus +"..getValue());
					else
						draginfo.setStringData(window.label.getValue().." Bonus "..getValue());
					end
					draginfo.setNumberData(getValue());
					return true;
				end

				function onInit()
					addSource("race");
					addSource("stat");
					addSource("item");
					addSource("special");
					addSource("misc");
					super.onInit();
				end

				function onSourceUpdate()
					local nValue = calculateSources();
					local node = window.getDatabaseNode();

					nValue = nValue + DB.getValue(node, "race", 0);
					nValue = nValue + DB.getValue(node, "stat", 0);
					nValue = nValue + DB.getValue(node, "item", 0);
					nValue = nValue + DB.getValue(node, "special", 0);
					nValue = nValue + DB.getValue(node, "misc", 0);
					setValue(nValue);
				end

				function onDoubleClick(x, y)
					ModifierStack.addSlot(window.label.getValue() .. " RR Bonus", getValue());
				end

				function onDragStart(button, x, y, draginfo)
					draginfo.setType("number");
					draginfo.setDescription(window.label.getValue().." RR Bonus");
					if getValue() >= 0 then
						draginfo.setStringData(window.label.getValue().." RR Bonus +"..getValue());
					else
						draginfo.setStringData(window.label.getValue().." RR Bonus "..getValue());
					end
					draginfo.setNumberData(getValue());
					return true;
				end

				function onInit()
					local node = window.getDatabaseNode();
					local resistances = DB.getValue(node, "resistances", "");
					addSource("item");
					addSource("misc");
					if string.find(resistances, "Essence") then
						addSource("...base.essence.total");
					end
					if string.find(resistances, "Channeling") then
						addSource("...base.channeling.total");
					end
					if string.find(resistances, "Mentalism") then
						addSource("...base.mentalism.total");
					end
					super.onInit();
				end

				function onSourceUpdate()
					local nValue = calculateSources();
					local nAverage = 0;
					local count = 0;
					local node = window.getDatabaseNode();
					local resistances = DB.getValue(node, "resistances", "");
					
					if string.find(resistances, "Essence") then
						nAverage = nAverage + DB.getValue(node, "...base.essence.total", 0);
						count = count + 1;
					end
					if string.find(resistances, "Channeling") then
						nAverage = nAverage + DB.getValue(node, "...base.channeling.total", 0);
						count = count + 1;
					end
					if string.find(resistances, "Mentalism") then
						nAverage = nAverage + DB.getValue(node, "...base.mentalism.total", 0);
						count = count + 1;
					end
					if count > 0 then
						nAverage = math.floor((nAverage / count) + 0.5);
					end

					nValue = nValue + nAverage + DB.getValue(node, "item", 0) + DB.getValue(node, "misc", 0);
					
					setValue(nValue);
				end

				function onDoubleClick(x, y)
					ModifierStack.addSlot(window.label.getValue() .. " RR Bonus", getValue());
				end

				function onDragStart(button, x, y, draginfo)
					draginfo.setType("number");
					draginfo.setDescription(window.label.getValue().." RR Bonus");
					if getValue() >= 0 then
						draginfo.setStringData(window.label.getValue().." RR Bonus +"..getValue());
					else
						draginfo.setStringData(window.label.getValue().." RR Bonus "..getValue());
					end
					draginfo.setNumberData(getValue());
					return true;
				end

				function onInit()
					addSource("abilities.quickness.total");
					addSource("initiative.misc");
					super.onInit();
				end

				function onSourceUpdate()
					local nValue = calculateSources();
					local node = window.getDatabaseNode();
					nValue = nValue + DB.getValue(node, "abilities.quickness.total", 0);
					nValue = nValue + DB.getValue(node, "initiative.misc", 0);
					setValue(nValue);
				end

				function onDoubleClick(x, y)
					ModifierStack.addSlot("Initiative Bonus", getValue());
				end

				function onDragStart(button, x, y, draginfo)
					draginfo.setType("number");
					draginfo.setDescription("Initiative Bonus");
					if getValue() >= 0 then
						draginfo.setStringData("Initiative Bonus +"..getValue());
					else
						draginfo.setStringData("Initiative Bonus "..getValue());
					end
					draginfo.setNumberData(getValue());
					return true;
				end
